-- ── Sourcegraph Cody ──────────────────────────────────────────────
UPDATE tools SET
  short_description = $q$Sourcegraph Cody is an enterprise AI coding assistant with codebase-aware chat, autocomplete, and search for large engineering teams.$q$,
  pricing_model = $q$Custom-Enterprise pricing$q$,
  starting_price = $q$Starting at $16,000/year (custom quote, scales with team size)$q$,
  founded_year = 2013,
  company_size = $q$~150-200 employees (fully remote)$q$,
  headquarters = $q$San Francisco, California, USA$q$,
  languages = ARRAY[$q$English$q$]::text[],
  seo_meta_description = $q$Sourcegraph Cody: enterprise AI coding assistant with codebase-aware chat, autocomplete, and search context for large engineering teams.$q$,
  og_description = $q$Sourcegraph Cody: enterprise AI coding assistant with codebase-aware chat, autocomplete, and search context for large engineering teams.$q$,
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f0a80f4d-54d7-42de-ad76-cecc618d9b90';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'f0a80f4d-54d7-42de-ad76-cecc618d9b90' AND logo IS NULL AND website IS NOT NULL;









