INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$AI Chat$q$, $q$A codebase-aware conversational assistant for understanding, writing, and fixing code, grounded in context from the organization's own repositories.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Auto-Edit (Autocomplete)$q$, $q$Contextual, cursor-aware code suggestions that appear as engineers type, based on the surrounding file and broader codebase context.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Context Engine / Deep Search$q$, $q$Draws on Sourcegraph's search API to retrieve relevant files, symbols, and cross-repository references for more accurate AI answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Context Filters$q$, $q$Admin-configurable controls over which repositories are permitted to inform Cody's chat and autocomplete responses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Prompts Library$q$, $q$Shareable, reusable prompt templates for automating recurring engineering tasks like code review, documentation, and debugging.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Debugging Assistance$q$, $q$Helps identify the source of errors within existing code and proposes fixes using surrounding codebase context.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$IDE and Code Host Integrations$q$, $q$Works inside VS Code, JetBrains IDEs, and Visual Studio, and integrates with GitHub and GitLab repositories.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$MCP Server, API, and CLI Access$q$, $q$Programmatic and agent-based access to Cody's capabilities for custom tooling and automation pipelines.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Enterprise Security and Admin Controls$q$, $q$Single-tenant cloud or self-hosted deployment options with enterprise-grade access management and admin oversight.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Batch Changes and Code Insights$q$, $q$Broader Sourcegraph platform tools for large-scale code changes and engineering analytics, bundled with Cody Enterprise.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Deep, codebase-wide context via Sourcegraph's search engine, not just the files open in the editor.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Strong fit for very large, multi-repository, multi-language enterprise codebases.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Enterprise deployment flexibility, including single-tenant cloud or fully self-hosted options.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Org-wide AI-credit pooling avoids per-seat usage friction across large teams.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Bundled with Sourcegraph's mature code-search, Batch Changes, and Insights tooling.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$No free or individual-developer tier; Cody Free and Cody Pro were discontinued in 2025.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Enterprise-only, annual-contract pricing starting near $16,000/year is a high floor for smaller teams.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Requires buy-in to the broader Sourcegraph platform rather than a lightweight standalone install.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Public pricing detail is limited; most buyers must contact sales for an exact quote.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Faces strong competition from lower-cost, self-serve assistants such as GitHub Copilot and Cursor.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Is there a free version of Sourcegraph Cody?$q$, $q$No. Sourcegraph discontinued the Cody Free and Cody Pro plans in 2025; Cody is now available only as part of Sourcegraph Enterprise. Individual developers looking for a free option are pointed to Sourcegraph's separate Amp product instead.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$How much does Cody cost?$q$, $q$Cody is sold as part of Sourcegraph Enterprise, with published pricing starting at $16,000 per year and scaling with team size and usage credits. Exact quotes require contacting Sourcegraph sales.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Which IDEs and code hosts does Cody support?$q$, $q$Cody integrates with VS Code, JetBrains IDEs, and Visual Studio, and works alongside repositories hosted on GitHub and GitLab.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Does Cody require the full Sourcegraph code-search platform?$q$, $q$Yes. In its current form, Cody is delivered as a capability within Sourcegraph Enterprise, alongside code search, Batch Changes, and Insights, rather than as a standalone product.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$What happened to Cody in the Enterprise Starter tier?$q$, $q$Sourcegraph removed Cody from the Enterprise Starter tier in 2025, so Cody is now offered only within the full Sourcegraph Enterprise plan.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Onboarding engineers into large monorepos$q$, $q$New hires use Cody chat to ask questions about unfamiliar services and get answers grounded in the actual codebase instead of generic explanations.$q$, $q$Engineering managers and onboarding teams at large organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Cross-repository debugging$q$, $q$Engineers use Cody's context-aware search to trace an error across multiple interconnected repositories and get a proposed fix without manually searching each service.$q$, $q$Platform and backend engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Standardizing AI tooling across many IDEs$q$, $q$Developer-experience teams roll out Cody across VS Code, JetBrains, and Visual Studio so every engineer gets a consistent, codebase-aware assistant regardless of editor choice.$q$, $q$Developer experience (DevEx) and platform engineering teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Automating recurring engineering workflows$q$, $q$Teams build and share Cody Prompts for repetitive tasks such as code-review checklists or documentation generation, reducing manual repetitive work.$q$, $q$Engineering leads standardizing team workflows$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Cody Enterprise$q$, $q$Starting at $16,000$q$, $q$Annual$q$, $q$["Codebase-wide search and navigation","AI chat, auto-edit, and Prompts","Deep Search context engine","Batch Changes, Insights, and Monitoring","MCP Server, API, and CLI access","Single-tenant cloud or self-hosted deployment","Enterprise-grade security and admin controls","24x5 support with premium upgrade options"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$Custom / Volume$q$, $q$Custom quote$q$, $q$Annual contract$q$, $q$["Volume-based pricing for larger engineering organizations","Org-wide AI-credit pooling with no monthly expiry","Dedicated account and solutions engineering support","Tailored deployment and SLA terms"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sourcegraph Cody is the AI coding assistant built by Sourcegraph, the code-intelligence company co-founded by Quinn Slack and Beyang Liu in 2013 and headquartered in San Francisco. Cody layers chat, contextual autocomplete-style "auto-edit" suggestions, and prompt automation on top of Sourcegraph's existing code-search engine, so answers are grounded in the context of an organization's actual repositories rather than generic training data pulled from the open internet.$q$, $q$Historically, Cody shipped in Free, Pro, and Enterprise Starter tiers alongside a full Enterprise edition, competing directly with editor-first assistants like GitHub Copilot for individual developer mindshare. In mid-2025, Sourcegraph retired the Free, Pro, and Enterprise Starter offerings to focus its engineering effort on two distinct products: Cody Enterprise for large organizations already running Sourcegraph's code-search platform, and a separate agentic coding tool called Amp aimed at individual and small-team developers who previously used the free and Pro tiers. Existing Free and Pro users were offered transition credits toward Amp as part of the wind-down.$q$, $q$As a result, Cody today is positioned squarely as an enterprise product rather than a consumer app. It is sold on annual contracts, with published pricing starting at $16,000 and scaling with team size and usage credits, bundled together with Sourcegraph's broader code-search, Batch Changes, and code-insights platform. Buyers evaluate Cody as part of a wider engineering-intelligence purchase rather than as a standalone monthly subscription, and most detailed quotes require a conversation with Sourcegraph's sales team rather than a self-serve checkout flow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$who-sourcegraph-cody-is-for$q$, $q$Who Sourcegraph Cody Is For$q$, 2, ARRAY[$q$Cody is built for engineering organizations that already rely on, or are actively evaluating, Sourcegraph's code-search platform to navigate large, multi-repository codebases. It suits companies with dozens to thousands of engineers spread across many services, where knowing which repository a given function or configuration lives in is a daily challenge rather than an occasional one.$q$, $q$It also fits security- and compliance-conscious enterprises that need single-tenant cloud or fully self-hosted deployment, administrative control over which repositories are allowed to feed AI responses through context filters, and centralized AI-credit pooling across an entire engineering organization rather than fragmented, per-seat billing that is harder to govern at scale.$q$, $q$Platform, developer-experience, and developer-productivity teams responsible for standardizing tooling across many IDEs (VS Code, JetBrains, Visual Studio) and code hosts (GitHub, GitLab) are a natural buyer, since Cody's value comes largely from codebase-wide context and organization-level administration rather than single-file autocomplete alone. Organizations already budgeting for Sourcegraph's code-search and Batch Changes tooling can add Cody as an incremental capability on the same annual contract, which simplifies procurement compared with introducing an entirely separate AI vendor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Individual developers, students, and open-source maintainers who want a free or low-cost AI pair programmer should look elsewhere: Sourcegraph discontinued Cody Free and Cody Pro in 2025, so there is no longer a self-serve sign-up or personal-use path into the product at all.$q$, $q$Small startups and solo founders on tight budgets will find the enterprise, annual-contract pricing model, starting near $16,000 per year and requiring a sales conversation, hard to justify next to lower-cost, month-to-month tools such as GitHub Copilot or Cursor that offer comparable in-editor assistance without a procurement process or a minimum contract size.$q$, $q$Teams that want a lightweight, agentic coding assistant without adopting Sourcegraph's broader code-search platform are better served by Sourcegraph's own Amp product or by other standalone assistants, since Cody is now sold strictly as part of the Enterprise package rather than as an à la carte add-on that a small team could purchase independently.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Cody's core surface is an in-IDE chat that answers questions about a codebase, explains unfamiliar code, and proposes fixes, paired with an auto-edit mode that offers contextual, cursor-aware code suggestions as engineers type rather than generic boilerplate completions.$q$, $q$Its context engine draws on Sourcegraph's search API to pull in relevant files, symbols, and cross-repository references rather than relying only on files open in the editor, and administrators can apply context filters to control which repositories are allowed to inform responses, which matters for organizations that handle sensitive, regulated, or otherwise access-restricted source code.$q$, $q$Beyond chat and autocomplete, Cody offers a library of shareable Prompts for automating recurring tasks such as code-review checklists, documentation generation, and debugging workflows, plus enterprise controls including MCP server, API, and CLI access, single-tenant or self-hosted deployment, and org-wide AI-credit pooling that carries over rather than expiring on a monthly cycle. These capabilities sit alongside the wider Sourcegraph platform's Batch Changes and Insights tooling, so Cody is one part of a broader engineering-intelligence suite rather than an isolated point solution.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', $q$the-sourcegraph-cody-experience$q$, $q$The Sourcegraph Cody Experience$q$, 2, ARRAY[$q$Day to day, engineers interact with Cody from inside their existing IDE, whether VS Code, a JetBrains IDE, or Visual Studio, or through GitHub and GitLab integrations, so the workflow stays close to where code is already written, reviewed, and shipped rather than requiring a separate tool or browser tab.$q$, $q$Because responses are grounded in Sourcegraph's indexed search of the organization's own repositories, answers tend to reference real internal functions, services, and naming conventions rather than generic examples, which is the main differentiator engineering teams cite versus editor-only assistants that only see the currently open file.$q$, $q$On the operations side, administrators get controls for managing seats, AI credits, and repository access, 24x5 support with premium upgrade options, and volume-based contract terms, reflecting that Cody is delivered and supported as a component of an enterprise platform rather than a self-serve subscription an individual engineer can start or cancel on their own initiative.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0a80f4d-54d7-42de-ad76-cecc618d9b90', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$AI text-to-speech narration$q$, $q$Converts articles, documents, PDFs, and ebooks into natural-sounding spoken audio with adjustable playback speed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Scan & Listen (OCR)$q$, $q$Uses optical character recognition to turn photos of printed pages or physical books into audio.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Large multilingual voice library$q$, $q$Premium unlocks a large library of AI voices spanning dozens of languages and accents.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Voice cloning$q$, $q$Lets users create a custom AI voice modeled on their own voice for personalized narration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$AI summaries and document chat$q$, $q$Generates quick summaries of long documents and lets users ask questions about the content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Voice typing / dictation$q$, $q$Converts spoken words into written text for faster note-taking and drafting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$AI podcast creation$q$, $q$Turns written content into podcast-style audio for on-the-go listening.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Cloud storage integrations$q$, $q$Connects with Google Drive, Dropbox, and Microsoft OneDrive to import documents directly for narration.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Cross-platform apps and browser extension$q$, $q$Available on web, iOS, Android, Mac, and Windows, plus a Chrome extension for reading web pages aloud.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Natural-sounding AI voices with adjustable speeds up to 5x$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Supports many input types: web pages, PDFs, ebooks, and scanned physical pages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Useful accessibility tool for users with dyslexia or reading difficulties$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Available across web, mobile, and desktop with a browser extension for convenience$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Separate Studio and API products extend the voice technology beyond personal reading$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Free tier is limited to slower speeds and fewer, more robotic-sounding voices$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Premium subscription cost may feel steep for occasional or light users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$AI voices can mispronounce uncommon words, names, or technical terms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Some advanced AI features depend on ongoing internet connectivity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Voice cloning and premium features add a learning curve for new users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Is Speechify free to use?$q$, $q$Speechify offers a free plan with basic text-to-speech at slower speeds and a limited voice selection. A paid Premium subscription unlocks faster speeds, more natural voices, and additional AI features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$What file types can Speechify read aloud?$q$, $q$Speechify can read web pages, PDFs, Word documents, ebooks, emails, and even photographed or scanned physical pages using its OCR-based Scan & Listen feature.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Does Speechify work on mobile devices?$q$, $q$Yes, Speechify has apps for iOS and Android, along with Mac and Windows desktop apps and a Chrome browser extension, so listening can continue across devices.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Can Speechify clone my own voice?$q$, $q$Speechify includes a voice cloning feature that lets users create a custom AI voice based on a sample of their own voice, available as part of its premium offerings.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Is Speechify good for people with dyslexia?$q$, $q$Speechify was originally created to help a student with dyslexia keep up with reading, and it remains commonly used as an accessibility tool for people with dyslexia and other reading challenges.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Accessible reading for students with dyslexia$q$, $q$Converts textbooks, articles, and assigned readings into spoken audio so students can follow along or listen instead of reading text visually.$q$, $q$Students and learners with dyslexia or reading-related learning differences$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Faster consumption of long documents$q$, $q$Lets professionals listen to reports, research papers, and PDFs at increased speeds during commutes or while multitasking.$q$, $q$Knowledge workers and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Turning physical books into audio$q$, $q$Uses OCR to scan printed pages or photographed text and narrate the content aloud, useful for material without a digital version.$q$, $q$Readers of physical books and printed materials$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Voiceover and podcast content creation$q$, $q$Applies Speechify's AI voice technology through Studio and API products to generate voiceovers, dubbing, and podcast-style audio from written scripts.$q$, $q$Content creators and small production teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Playback speeds up to 1.5x","10 standard voices","Text-to-speech on web and mobile"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Premium (Monthly)$q$, $q$$29/month$q$, $q$Monthly$q$, $q$["1000+ natural AI voices","60+ languages","Playback speeds up to 5x","Scan & Listen OCR","AI summaries and document chat","Voice typing and AI podcast creation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Premium (Annual)$q$, $q$$139/year (about $11.58/month)$q$, $q$Annual$q$, $q$["Same features as monthly Premium at a reduced effective monthly rate","1000+ natural AI voices and 60+ languages","Playback speeds up to 5x","Cloud storage integrations with Google Drive, Dropbox, and OneDrive"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$Studio & API$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["AI voiceover and dubbing tools for video and audio production","Developer API for integrating Speechify voices into third-party apps","Custom usage terms based on volume and use case"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Speechify is a text-to-speech application that converts articles, PDFs, ebooks, emails, and scanned documents into spoken audio. Founded by Cliff Weitzman, who built the first version to help himself keep up with college reading as a student with dyslexia, the product has grown into a broader reading and productivity tool used across desktop, mobile, and browser environments by millions of everyday readers.$q$, $q$At its core, Speechify uses AI-generated voices to narrate written text at adjustable speeds, letting users listen instead of read. Beyond basic narration, the platform has expanded into optical character recognition for physical books, AI-generated summaries, voice cloning, and dictation, positioning it as an all-purpose voice and reading assistant rather than a single-feature text-to-speech tool aimed at one narrow use case. This broader scope reflects a shift in the product from a simple reading aid toward a wider voice-and-productivity suite.$q$, $q$The company offers a free tier with limited voices and speeds, alongside a paid Premium subscription that unlocks a larger voice library, faster playback, and AI features such as summarization and chat. Separate offerings, Speechify Studio and a developer API, extend the same underlying voice technology into video voiceovers, audio dubbing, and third-party app integrations for teams building their own products. Together these tiers let the same core technology serve casual readers and commercial audio producers alike.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$who-speechify-is-for$q$, $q$Who Speechify Is For$q$, 2, ARRAY[$q$Speechify is aimed squarely at people who read large volumes of text and want an audio alternative. Students juggling textbooks and course readings, especially those with dyslexia or other reading-related learning differences, are a core audience the product was originally built to serve, and it remains a popular accessibility tool in that space today.$q$, $q$Knowledge workers, researchers, and professionals who need to get through long reports, articles, or PDFs during commutes or while multitasking are another natural fit. The ability to speed up playback, switch between devices, and pull documents straight from cloud storage makes it useful for anyone trying to reclaim time that would otherwise go to silent reading at a desk, turning idle moments throughout the day into productive reading time.$q$, $q$Content creators and small teams also use Speechify's voice technology for narration, voiceovers, and podcast-style audio through its Studio and API products, making the tool relevant beyond individual reading assistance and into lightweight audio production workflows for marketing, video, and independent media projects. Developers looking to add spoken-word features to their own apps can likewise tap the underlying API rather than building voice synthesis from scratch.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users who only need occasional, basic text-to-speech, such as reading a short article once in a while, may find the free tier's slower speeds and robotic-sounding voices limiting, while the Premium subscription cost may not be justified for such light, infrequent use compared with a browser's built-in reading tools.$q$, $q$Teams that need precise control over voice production quality, such as broadcast-grade narration with fine-tuned pacing and emotional delivery, may find general-purpose AI voices less suitable than specialized professional voiceover software or human talent for high-stakes, polished commercial projects.$q$, $q$Organizations with strict data-handling requirements for sensitive or regulated documents should evaluate Speechify's data policies carefully before uploading confidential files, since the product is designed primarily for everyday reading rather than as a compliance-focused enterprise document platform with dedicated data-residency guarantees. Buyers comparing dedicated enterprise document or compliance tools should weigh those requirements against Speechify's consumer-oriented focus before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Speechify's core feature is natural-sounding AI text-to-speech, letting users listen to web pages, documents, PDFs, and ebooks at adjustable speeds. Premium unlocks a much larger voice library, spanning dozens of languages and accents, plus faster playback speeds compared with the free tier's limited, slower options.$q$, $q$Scan & Listen uses optical character recognition to turn photos of printed pages or physical books into audio, while integrations with Google Drive, Dropbox, and Microsoft OneDrive let users pull documents directly into the app for narration without manual uploads, keeping reading lists synced across a person's existing file storage and reducing the friction of moving files between apps.$q$, $q$Additional AI-driven features include document summaries and chat for quickly digesting long content, voice typing for hands-free dictation, voice cloning for a personalized narrator, and AI podcast creation. A browser extension, mobile apps, and desktop apps keep the reading experience consistent across devices and picking up where a user left off, syncing playback position between phone, browser, and desktop sessions.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', $q$the-speechify-experience$q$, $q$The Speechify Experience$q$, 2, ARRAY[$q$Using Speechify typically starts with importing or opening a piece of text, whether that's a webpage via the browser extension, a PDF, or a photographed page, and then pressing play. The interface highlights words as they are read aloud, which helps with following along and comprehension, especially for readers who benefit from a visual anchor alongside the audio.$q$, $q$The jump from the free tier to Premium is noticeable: voices sound considerably more natural, playback can run several times faster, and features like AI summaries, voice cloning, and voice typing become available. Many users describe the transition as changing the app from a novelty into a daily productivity habit woven into commutes, workouts, and study sessions.$q$, $q$Overall, the experience is built around convenience and speed, letting people consume more written material passively during commutes, chores, or other tasks. The trade-off is that, like any AI voice, even the best Speechify voices can occasionally mispronounce uncommon words, names, or technical jargon, requiring users to adjust expectations rather than expect flawless narration in every scenario.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6ef381d0-f2eb-4c4f-bf13-583a63f2091b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
