INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$POS Hardware and Software$q$, $q$Countertop terminals, handheld devices, and kitchen display integration for restaurant and retail order flows, including table and menu management.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Payment Processing$q$, $q$Built-in card processing with tiered in-person and keyed-in rates, plus financing options for purchasing hardware over time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$SpotOn Order$q$, $q$Commission-free online ordering connected directly to the POS and kitchen, so orders flow through without a third-party marketplace cut.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$SpotOn Reserve$q$, $q$Table reservation and guest management tools built for full-service restaurants.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Marketing Assist$q$, $q$Centralized email and SMS marketing campaigns and online review management from a single dashboard.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$SpotOn Teamwork$q$, $q$Scheduling, tip management, and payroll integration synced to POS sales data for labor management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Reporting and Analytics$q$, $q$Sales, labor, and profitability dashboards for single-location and multi-location businesses.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Menu and Table Management$q$, $q$Digital menu editing and table layout tools used by service staff during daily operations.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Developer API and Integrations$q$, $q$OAuth-based API and partner integrations connecting accounting, e-commerce, and marketing tools such as QuickBooks and Shopify.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$GoTo Place App$q$, $q$A white-labeled, guest-facing ordering app tied to a business's own branding.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Bundles POS hardware, payments, online ordering, and marketing under one vendor and dashboard.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Commission-free online ordering keeps more of each sale compared with third-party delivery marketplaces.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Dedicated sales and support representatives assist with setup rather than a purely self-serve flow.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Built-in labor and payroll tools through SpotOn Teamwork reduce the need for separate scheduling software.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Multiple pricing tiers let merchants trade off monthly software fees against card-processing rates.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Pricing isn't fully published; getting an exact quote requires a sales conversation.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Lower-cost plans can require multi-year contracts and processing minimums.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Primarily built for the US market, which limits fit for international merchants.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Switching to SpotOn's proprietary hardware and menu setup involves an onboarding and migration period.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Add-on modules like marketing and labor management carry additional monthly costs on top of core POS fees.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$What kind of businesses use SpotOn?$q$, $q$SpotOn is used mainly by restaurants (full-service and quick-service), bars, and retail or service businesses like salons that need integrated POS, payments, online ordering, and marketing tools.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$How much does SpotOn cost?$q$, $q$Pricing varies by plan: published tiers include a $0/station/month option with higher processing rates and multi-year terms, and a $55/station/month option with lower processing rates on a month-to-month basis. Exact costs depend on a custom quote from SpotOn's sales team.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Does SpotOn offer a free trial?$q$, $q$SpotOn does not widely advertise a standard free trial. Instead it offers sales demos and consultations, and one of its plans has no monthly software fee but comes with contract and processing-volume requirements.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Does SpotOn have an API for integrations?$q$, $q$Yes. SpotOn provides a developer center and an OAuth-based API that partners and businesses can use to connect accounting, e-commerce, and other third-party software.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$What hardware does SpotOn support?$q$, $q$SpotOn sells its own proprietary terminals and handheld devices, along with kiosk options, and offers financing so merchants can spread hardware costs over time instead of paying entirely upfront.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Full-service restaurant table management$q$, $q$Combine POS ordering, table layouts, and SpotOn Reserve reservations in one system to manage front-of-house operations end to end.$q$, $q$Full-service restaurant owners and managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Quick-service and counter ordering$q$, $q$Use commission-free SpotOn Order alongside counter POS terminals to handle high-volume, fast-turnaround orders without marketplace fees.$q$, $q$Quick-service and fast-casual operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Multi-location labor and payroll management$q$, $q$Run scheduling, tip tracking, and payroll through SpotOn Teamwork synced to POS sales data across several locations.$q$, $q$Multi-unit restaurant and retail groups$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Retail and service business checkout$q$, $q$Process in-person payments and manage inventory or service bookings through SpotOn's POS hardware and software outside of restaurants.$q$, $q$Small retail shops and service businesses like salons$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$All-In$q$, $q$$0 per station$q$, $q$Monthly (2-year minimum term)$q$, $q$["POS hardware and software included","Higher card-processing rates","Online ordering and table management","24/7 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$POS Essentials$q$, $q$$55 per station$q$, $q$Monthly, month-to-month$q$, $q$["Lower card-processing rates","Hardware financing options","Menu and table management","Reporting and 24/7 support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Build Your Own (Multi-Unit/Enterprise)$q$, $q$Custom$q$, $q$Custom$q$, $q$["Tailored software bundle","Custom processing rates","Multi-location support","Dedicated account management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Core Add-On Bundle$q$, $q$$50/month + 0.20% of processing volume (capped at $200)$q$, $q$Monthly$q$, $q$["Profit Assist analytics","SpotOn Order online ordering","GoTo Place guest app","Marketing Assist"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SpotOn is a point-of-sale and business management platform built primarily for restaurants and retail businesses, combining payment processing, POS hardware, online ordering, and marketing tools into one system. Founded in 2017 and headquartered in San Francisco, the company positions itself as an alternative to legacy POS vendors, pairing its software with human account representatives rather than a purely self-service signup flow.$q$, $q$The platform spans full-service and quick-service restaurants, bars, retail shops, salons, and other small to midsize businesses, offering countertop terminals, handheld devices, and kiosk hardware alongside cloud-based software for menu management, table service, and reporting. Add-on modules extend the core POS to cover commission-free online ordering, reservations, marketing campaigns, and payroll and labor management.$q$, $q$Rather than a single flat subscription, SpotOn sells bundled hardware-plus-software packages across several tiers, ranging from lower monthly fees paired with higher card-processing rates to higher monthly software fees paired with lower processing rates. Getting an exact price generally requires speaking with a sales representative, who tailors the quote to business type, location count, and expected processing volume.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$who-spoton-is-for$q$, $q$Who SpotOn Is For$q$, 2, ARRAY[$q$SpotOn suits independent restaurant owners and small multi-location groups who want a single vendor for payments, POS hardware, online ordering, and marketing rather than stitching together separate tools. Businesses that value a dedicated setup and ongoing support relationship, instead of an instant self-serve account creation flow, tend to fit the model well.$q$, $q$Retailers and service businesses, including bars, cafes, salons, and specialty shops, that need integrated hardware such as handheld ordering devices, kitchen display systems, or kiosks also fall within SpotOn's target market, since the company builds and supports its own terminal lineup rather than relying solely on third-party hardware.$q$, $q$Owners who want built-in labor management, tip tracking, and payroll alongside their POS, or who want commission-free online ordering tied directly to their menu and kitchen, are well matched to SpotOn's bundled approach, since these modules are designed to work natively with the core POS rather than as bolt-on integrations added later.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses outside the United States, or those needing a POS with mature, well-documented international payment support, should look elsewhere, since SpotOn's payments and hardware distribution focus on the US market. Purely e-commerce operations with no in-person sales component will also find much of the hardware-centric feature set unnecessary for their day-to-day operations.$q$, $q$Owners who want fully transparent, self-service pricing published as fixed dollar figures without a sales conversation may find SpotOn's custom-quote process frustrating, since final costs depend on negotiated processing rates, contract length, and the chosen hardware bundle rather than a single published price list.$q$, $q$Very small or seasonal merchants who only need a basic mobile card reader and no back-of-house software, or who want to avoid the multi-year contract terms tied to some lower-cost plans, may be better served by simpler, contract-free mobile payment tools rather than a full restaurant and retail management platform like SpotOn.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, SpotOn provides POS hardware and software for restaurants and retail, covering order entry, table and menu management, kitchen display routing, and integrated card payment processing with tiered in-person and keyed-in rates.$q$, $q$On top of the base POS, SpotOn layers commission-free online ordering through SpotOn Order, table reservations through SpotOn Reserve, and a marketing module that centralizes email and SMS campaigns and review management from one dashboard, all designed to sync back into the same guest and sales data rather than operating as separate silos.$q$, $q$For labor-intensive operations, SpotOn Teamwork adds scheduling, tip management, and payroll integration synced directly to POS sales, while a developer center and OAuth-based API let businesses and partners connect accounting, e-commerce, and other third-party software into the platform.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$the-spoton-experience$q$, $q$The SpotOn Experience$q$, 2, ARRAY[$q$Getting started with SpotOn typically involves a sales conversation and account setup process rather than an instant self-service signup, with a representative helping select hardware, a pricing tier, and add-on modules before installation and staff training take place.$q$, $q$Once running, users generally interact with SpotOn through countertop or handheld terminals in-store and a web-based back-office dashboard for reporting, menu edits, marketing, and staff scheduling. SpotOn has built a reputation among review sites like G2 and Capterra for responsive customer support compared with some larger competitors in the category.$q$, $q$As with any full-service POS switch, businesses should expect a learning curve during onboarding and menu or system migration, plus some contract commitment depending on the pricing tier chosen. Many owners cite the combination of hardware, software, and dedicated support as a meaningful trade-off versus assembling multiple point solutions on their own.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
