INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Domain Overview$q$, $q$Enter any competitor's domain to see its organic and paid keyword counts, estimated monthly search traffic, and estimated PPC budget in one dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Competitor Keyword Research$q$, $q$Discover the exact keywords a competitor ranks for organically or bids on in paid search, along with ranking position and estimated value.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Ad History$q$, $q$Review years of a competitor's historical Google Ads copy variations and estimated ad spend to study which messaging has run the longest.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Kombat Tool$q$, $q$Compare keyword overlap between your domain and up to several competitors using a Venn-diagram visualization to spot content and ranking gaps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Rank Tracking$q$, $q$Monitor keyword ranking positions over time across search engines, with tracking allowances that scale by plan tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Backlink Analysis$q$, $q$View a domain's inbound backlink profile to understand which sites are linking to competitors and where link-building opportunities exist.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$PPC Keyword and Ad-Group Recommendations$q$, $q$Get suggested keywords and ad-group structures for building or refining Google Ads campaigns based on competitor performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Custom Branded Reporting$q$, $q$Generate white-labeled PDF or exportable reports for client-facing agency work on higher-tier plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$RivalFlow$q$, $q$An AI-assisted feature that surfaces content and keyword recommendations based on where competitors are already ranking.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$API Access$q$, $q$Pull SpyFu keyword and competitor data programmatically into other systems, available on higher-tier plans.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Deep historical ad archive spanning many years of competitor Google Ads copy and spend estimates$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Simple, approachable interface compared to denser enterprise SEO suites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Lower entry-level pricing than many competing SEO/PPC platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Combines organic SEO and paid search competitor data in a single tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Free account tier lets new users search and preview data without a credit card$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Keyword and backlink database is generally smaller than larger suites like Semrush or Ahrefs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Rank tracking is capped by plan tier, requiring an upgrade for larger keyword lists$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$No dedicated mobile app for on-the-go access$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Data coverage and interface are strongest for English-language, US-centric search markets$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Lacks the technical SEO auditing and site-crawling depth of dedicated technical SEO tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Is SpyFu free to use?$q$, $q$SpyFu offers a free account with no credit card required, letting users search domains and keywords with limited data. Full keyword exports, unlimited searches, and rank tracking require a paid subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$What is SpyFu mainly used for?$q$, $q$SpyFu is used for competitor keyword research, PPC ad intelligence, and SEO rank tracking, helping marketers see what keywords and ads competitors are using in organic and paid search.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$How much does SpyFu cost?$q$, $q$Paid plans start around $39 per month billed monthly, with a mid-tier plan around $119 per month and an agency-focused plan around $249 per month; annual billing typically reduces the effective monthly price.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Does SpyFu offer a free trial or refund?$q$, $q$SpyFu provides a free account tier for basic searches and backs paid subscriptions with a 30-day money-back guarantee if a customer is not satisfied.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$How does SpyFu compare to Semrush or Ahrefs?$q$, $q$SpyFu generally has a smaller keyword and backlink index than Semrush or Ahrefs but is priced lower and is often considered easier to learn, with a particularly deep historical PPC ad archive.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Competitor PPC Research$q$, $q$Analyze which keywords and ad copy competitors are bidding on and running in Google Ads, including historical ad variations and estimated spend.$q$, $q$PPC specialists and paid search marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$SEO Keyword Gap Analysis$q$, $q$Use the Kombat tool and domain overview to find organic keywords competitors rank for that a site does not yet target.$q$, $q$SEO specialists and content marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Ad Copy and Messaging Inspiration$q$, $q$Study which of a competitor's ad variations have run longest as a signal for effective messaging to inform new campaigns.$q$, $q$Marketing teams building ad campaigns$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Client Rank Tracking and Reporting$q$, $q$Track keyword rankings for multiple client domains and generate branded reports summarizing competitor positioning.$q$, $q$Marketing agencies managing multiple accounts$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Basic$q$, $q$$39/month$q$, $q$Monthly (discounted rate available with annual billing)$q$, $q$["Unlimited keyword and domain searches","Data exports","Rank tracking for up to 5,000 keywords","Organic and paid keyword research"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Professional (Pro + AI)$q$, $q$$119/month$q$, $q$Monthly (discounted rate available with annual billing)$q$, $q$["Everything in Basic","RivalFlow AI content and keyword recommendations","Custom branded reporting","API access","Rank tracking for up to 15,000 keywords"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$Team/Agency$q$, $q$$249/month$q$, $q$Monthly (discounted rate available with annual billing)$q$, $q$["Everything in Professional","Rank tracking for up to 50,000 keywords","Five user logins","Daily rank update snapshots","Unlimited custom reporting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SpyFu is a competitor keyword research and PPC/SEO intelligence platform founded in 2006 and headquartered in Scottsdale, Arizona. It was built around a simple idea: type any domain into a search box and immediately see the organic and paid keywords that domain ranks for, an estimate of its monthly search traffic and Google Ads budget, and a record of the ads it has run. Nearly two decades later, that single search experience is still the core of the product.$q$, $q$Rather than positioning itself as a broad, all-in-one marketing suite, SpyFu deliberately narrows its focus to competitive intelligence: keyword overlap between domains, historical PPC ad copy and spend, rank tracking, and backlink visibility. The company remains a small, privately held business that sells subscriptions directly through tiered monthly and annual plans rather than through enterprise sales negotiations, and it markets itself primarily to individual marketers, freelancers, and small agencies rather than large enterprise buyers.$q$, $q$SpyFu sits in the same competitive-research category as Semrush, Ahrefs, and SimilarWeb, but it differentiates on price and on the depth of its historical advertising archive, which spans well over a decade of ad copy and spend estimates for millions of domains. That archive, combined with a lower price point than most rivals, is the feature most often cited by longtime users as the reason they keep a SpyFu subscription alongside or instead of larger SEO suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$who-spyfu-is-for$q$, $q$Who SpyFu Is For$q$, 2, ARRAY[$q$SpyFu is aimed at small and mid-sized marketing teams, freelance SEOs, PPC specialists, and boutique marketing agencies that need to understand what competitors are doing in organic and paid search without paying enterprise SEO-suite prices. Its interface is deliberately simple, so someone who is new to SEO or paid search advertising can search a competitor's domain and get useful, readable answers within minutes rather than needing training to interpret the data.$q$, $q$Agencies managing several client accounts get particular value from the higher-tier plans, which add multiple user logins, custom branded reporting, and larger rank-tracking keyword allowances, letting account managers pull competitor insights and present them directly inside client-facing reports without needing a separate reporting tool. This makes SpyFu a common fit for agencies that want one login shared across a small team.$q$, $q$Solo consultants, small in-house marketing hires, and e-commerce owners also use SpyFu as an affordable alternative to pricier platforms, relying on it mainly for competitor keyword discovery, PPC ad research, and periodic rank checks rather than for deep technical SEO auditing or large-scale content operations. For these users, the appeal is getting a focused, competitor-centric view of the search landscape without paying for a full enterprise toolkit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises and agencies that need deep technical SEO auditing, site-crawling, log-file analysis, or large-scale content optimization will likely find SpyFu too narrow, since it lacks the crawling, technical-audit, and content-workflow depth found in tools such as Semrush, Ahrefs, or Screaming Frog. Teams whose primary need is fixing on-site technical issues rather than researching competitors are better served elsewhere.$q$, $q$Teams that require the broadest possible keyword or backlink index, or that operate mainly outside English-speaking, US-centric search markets, may find SpyFu's data coverage thinner than competitors that index a wider set of international search engines and languages. Businesses with a strong international SEO focus should evaluate SpyFu's coverage for their specific markets before committing to a plan.$q$, $q$Organizations that want a single platform covering social media scheduling, content publishing, technical audits, and keyword research together should also look elsewhere, since SpyFu is intentionally scoped to keyword research, PPC intelligence, and competitor tracking rather than serving as an all-in-one marketing stack. Buyers expecting an enterprise-style suite with dedicated account management may also find SpyFu's self-serve, subscription model a mismatch for their procurement process.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, SpyFu's domain overview shows any website's organic ranking keywords, estimated monthly search traffic, and estimated paid search budget in a single dashboard, making it fast to size up a competitor before digging into specifics. From that overview, users can drill into individual keywords to see ranking history, estimated click-through value, and which competing domains also rank for the same terms.$q$, $q$The Kombat tool visualizes keyword overlap between multiple domains as a Venn diagram, helping users quickly spot keywords a competitor ranks for that they do not, while Ad History reconstructs years of a competitor's Google Ads copy and spend estimates so marketers can study which ad variations have run longest, a signal often used as a proxy for what messaging is converting well.$q$, $q$Rounding out the toolset are rank tracking for monitoring keyword positions over time across search engines, backlink and SERP feature analysis, PPC keyword and ad-group recommendations for building out Google Ads campaigns, custom branded PDF reporting for client-facing agency work, and RivalFlow, an AI-assisted feature that generates content and keyword recommendations based on how competitors are already ranking.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb2fc581-be51-4423-a4e1-a32e3a5ab109', $q$the-spyfu-experience$q$, $q$The SpyFu Experience$q$, 2, ARRAY[$q$Using SpyFu typically starts with a single search: enter a domain or keyword and the tool immediately returns organic and paid keyword data without requiring an account first, which lowers the barrier for a first look at what the product can do before anyone commits to a paid plan.$q$, $q$The dashboard favors clear tables and straightforward visualizations over dense, enterprise-style reporting, and most day-to-day tasks, such as pulling a competitor's top keywords, exporting a keyword list, or checking an ad's run history, can be completed in a handful of clicks without a steep learning curve. New users tend to find the product approachable largely because it avoids overwhelming them with every possible metric at once.$q$, $q$Paid plans unlock unlimited searches, larger data exports, and expanded rank tracking, and the overall experience scales reasonably well, from a single freelancer checking a handful of competitors up to an agency team tracking rankings and building reports across many client accounts, though larger teams with heavier data or technical-audit needs may eventually outgrow what SpyFu alone can provide.$q$]::text[], 4);
