INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Point of Sale Software$q$, $q$Customizable checkout software with modes tailored to retail, restaurants, and other business types.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Card Readers and Terminals$q$, $q$A range of hardware from low-cost magstripe readers to standalone Square Terminal and Register devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Online Store$q$, $q$Build an e-commerce website with orders and inventory synced to in-person sales.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Invoicing$q$, $q$Send digital invoices with online payment collection and automated payment reminders.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Inventory Management$q$, $q$Track stock across locations and sales channels with low-stock alerts and reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Team Management and Payroll$q$, $q$Schedule staff, track hours, set permissions, and run payroll from the same account.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Square Capital$q$, $q$Apply for business financing based on sales history, repaid as a percentage of daily sales.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Square Banking$q$, $q$Business checking and savings accounts with fast access to revenue from card sales.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Appointments$q$, $q$Online booking, calendar management, and reminders for salons, spas, and service businesses.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Loyalty and Marketing$q$, $q$Built-in loyalty programs plus email and SMS marketing tools to drive repeat business.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Free POS software with no monthly fee required to start accepting payments.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Transparent, flat-rate processing fees with no long-term contracts.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Fast sign-up and same-day setup with minimal underwriting.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Broad ecosystem covering payments, online sales, invoicing, payroll, and banking in one account.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Vertical-specific POS modes for restaurants, retail, and appointment-based businesses.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Flat-rate processing fees can cost more than negotiated rates for high-volume merchants.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Only available in a limited number of countries.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Square can hold or review funds for accounts flagged for unusual activity.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Some advanced features require the paid Plus or Premium subscription tiers.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Customization and third-party integration depth are more limited than fully open payment platforms.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Is Square free to use?$q$, $q$Yes, Square Free costs $0 per month per location and includes POS software, an online store, invoicing, and Square Banking; instead of a subscription, you pay a per-transaction processing fee.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$What payment processing fees does Square charge?$q$, $q$Fees vary depending on the plan and how a payment is taken, whether in person, online, or keyed in, and Square Premium subscribers get the lowest processing rates. Current rates are listed on Square's pricing page.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$What countries does Square support?$q$, $q$Square is currently available in the United States, Canada, the United Kingdom, Australia, Japan, Ireland, France, and Spain.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Does Square offer a free trial for paid plans?$q$, $q$Yes, the Square Plus and Square Premium subscription tiers each include a 30-day free trial before billing begins.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$What is the difference between Square and Block, Inc.?$q$, $q$Block, Inc. is the publicly traded parent holding company, which also owns Cash App and Afterpay, while Square is the seller-facing commerce and payments brand under that umbrella.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Retail Checkout and Inventory$q$, $q$A boutique or retail store uses Square POS with barcode scanning and inventory synced between its physical shop and online store.$q$, $q$Small retailers and shop owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Restaurant and Quick-Service Ordering$q$, $q$A cafe or restaurant runs Square for Restaurants for table management, course timing, and split checks alongside online ordering.$q$, $q$Restaurants, cafes, and food trucks$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Service and Appointment Booking$q$, $q$A salon or spa uses Square Appointments to let clients book online, pay deposits, and receive automated reminders.$q$, $q$Salons, spas, and other appointment-based businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Freelance Invoicing and On-the-Go Payments$q$, $q$A freelancer or contractor sends free digital invoices and accepts card payments in person with a mobile reader.$q$, $q$Freelancers, consultants, and solo service providers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Free$q$, $q$$0/month per location$q$, $q$Monthly$q$, $q$["POS software for in-person and online sales","Online store and online ordering","Invoicing","Square Banking checking and savings","Pay-per-transaction processing fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Plus$q$, $q$$49/month per location$q$, $q$Monthly (30-day free trial)$q$, $q$["Everything in Free","Advanced POS modes for restaurants, retail, salons, and bars","Advanced inventory management","Loyalty programs","Staff management tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$Premium$q$, $q$$149/month per location$q$, $q$Monthly (30-day free trial)$q$, $q$["Everything in Plus","Lowest processing rates","Premium customer support","Full suite of advanced business tools"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Square was founded in 2009 by Jack Dorsey and Jim McKelvey, initially known for its small white card reader that plugged into a phone's headphone jack and let anyone accept card payments without a traditional merchant account or lengthy bank application. That simple hardware innovation removed a major barrier for small businesses, market vendors, and independent sellers who previously had no affordable, fast way to take card payments outside of cash.$q$, $q$Since then, Square has grown from a single card reader into a full commerce ecosystem that includes point-of-sale software, e-commerce tools, invoicing, payroll, business financing, and banking services. In 2021 the parent company renamed itself Block, Inc., which now also owns Cash App and the buy-now-pay-later provider Afterpay, while the Square brand remains the seller-facing commerce and payments platform used by businesses day to day.$q$, $q$Square is headquartered in San Francisco, California, and serves sellers ranging from solo freelancers to multi-location retail and restaurant chains. Its products combine physical hardware, such as card readers, standalone terminals, and full point-of-sale registers, with a cloud-based dashboard that ties together sales, inventory, payments, and customer data across in-person and online channels, so a business can manage most of its day-to-day operations from one connected account rather than juggling several disconnected tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$who-square-is-for$q$, $q$Who Square Is For$q$, 2, ARRAY[$q$Square is built for independent retailers, cafes, restaurants, bars, salons, food trucks, and other small businesses that want to start accepting card payments quickly without signing a long-term merchant contract or navigating the complex underwriting typical of traditional bank merchant accounts. Its low upfront cost and flexible, no-contract model make it approachable for first-time business owners.$q$, $q$It also suits small multi-location businesses that need centralized reporting alongside vertical-specific tools, such as table management and course timing for restaurants, barcode-based inventory for retailers, or online booking and deposits for appointment-based services like salons and spas. Owners who want one consistent system across every location, rather than separate tools per site, tend to get the most value from Square's unified, cross-location reporting and permissions.$q$, $q$Freelancers, contractors, and solo service providers who occasionally need to invoice clients or take an in-person card payment benefit from Square's free tools and pay-as-you-go processing fees, since there is no monthly subscription required to get started, and hardware costs stay low for anyone selling only occasionally. This makes Square a practical fit for seasonal sellers, market stalls, and side businesses that cannot justify a fixed monthly software cost.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger enterprises with complex multi-entity accounting, deep ERP integrations, or highly customized workflow requirements may find Square's ecosystem more prescriptive than the open, fully configurable platforms typically built for that scale, and may need to weigh Square's API against a more bespoke, custom-built commerce stack assembled from specialized vendors.$q$, $q$Merchants with very high monthly transaction volumes may find Square's flat-rate processing fees more expensive than an interchange-plus rate negotiated directly with a traditional payment processor or bank, so it is worth comparing total processing costs, including hardware and subscription fees, before committing to Square as a primary payments provider.$q$, $q$Businesses operating outside Square's supported markets, currently the United States, Canada, the United Kingdom, Australia, Japan, Ireland, France, and Spain, cannot use Square as their main payments provider and should evaluate processors that are actually available and compliant in their own country instead, since account eligibility depends on where a business is legally registered.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Square offers point-of-sale software that runs on Square-branded terminals, registers, and stands, as well as third-party iOS and Android devices, handling sales, tax, discounts, refunds, and receipts through a single, consistent checkout interface that can be tailored to a specific type of business.$q$, $q$Beyond checkout, Square's commerce tools extend to an online store builder, integrated invoicing with online payment collection, inventory that syncs across in-person and online channels, appointment scheduling with reminders, and built-in loyalty and marketing programs designed to bring customers back and grow repeat revenue over time.$q$, $q$A financial services layer rounds out the platform, including Square Banking checking and savings accounts, Square Capital financing based on a business's own sales history rather than a traditional credit check, and payroll tools for paying and managing a team, all accessible from the same dashboard used for daily payments and reporting, which reduces the need to reconcile numbers across separate financial systems.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', $q$the-square-experience$q$, $q$The Square Experience$q$, 2, ARRAY[$q$Getting started with Square is designed to be fast: a business can sign up online, order an affordable card reader, download the app, and begin accepting payments the same day, without the lengthy underwriting process typical of traditional bank merchant accounts and processors. Many owners describe the initial setup as closer to installing a consumer app than opening a business banking relationship.$q$, $q$The Square dashboard unifies sales reporting, inventory, staff activity, and customer information in one place, giving owners a single view of the business instead of juggling separate systems. Square's current three-tier subscription structure, Free, Plus, and Premium, consolidated a previously fragmented set of a la carte add-on subscriptions into simpler, more predictable monthly bundles that are easier to budget for.$q$, $q$Support resources include an online help center, community forum, and phone or chat support, with Premium subscribers receiving elevated, more responsive support alongside the platform's lowest available processing rates, while Free and Plus users still retain access to standard support channels and the same core set of hardware and software, so no seller is locked out of basic help.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
