INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9aaf51c9-b792-42f0-8f4d-c00a00023f84', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Text-to-image generation$q$, $q$Creates original images from natural-language text prompts using a diffusion-based model architecture.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Image-to-image transformation$q$, $q$Takes an existing image plus a prompt and produces a modified or stylized variant of it.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Inpainting$q$, $q$Edits or replaces a selected region of an image while keeping the rest of the composition intact.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Outpainting$q$, $q$Extends an image beyond its original frame, generating new content that blends with the existing edges.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Open model weights$q$, $q$Publicly available weights let developers download, inspect, and run the model outside of Stability AI's own infrastructure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Fine-tuning support$q$, $q$The open architecture supports training custom styles, subjects, or domains on top of the base model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Developer API$q$, $q$A hosted, credit-based API exposes multiple model tiers for integrating generation into external applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Stable Assistant app$q$, $q$A consumer-facing chat and image interface that wraps Stability AI's models for users who prefer not to self-host.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Community ecosystem$q$, $q$A large ecosystem of third-party checkpoints, extensions, and control tools has grown up around the open model.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Open weights allow self-hosting, inspection, and full control over deployment$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Can be fine-tuned or customized for specific styles and use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Backed by a large, active community producing extensions and custom models$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Multiple access paths, from free self-hosting to paid hosted API and apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$No strict dependency on a single vendor's hosted service to keep using the model$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Self-hosting requires a capable GPU and some technical setup knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Getting high-quality results often requires prompt and parameter experimentation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Content moderation and safety filtering are largely the operator's responsibility when self-hosted$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Hosted API and Stable Assistant costs scale with usage, which can add up for heavy users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$The variety of community models and tools can be overwhelming for newcomers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Is Stable Diffusion free to use?$q$, $q$The underlying model weights are open and can be run for free on your own hardware, though Stability AI also offers paid, usage-based API access and subscription apps like Stable Assistant for people who prefer a hosted option.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Do I need a powerful computer to run Stable Diffusion myself?$q$, $q$Self-hosting generally benefits from a dedicated GPU with sufficient memory; users without suitable hardware typically rely on Stability AI's hosted API or app instead.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$What is the difference between Stable Diffusion and Stable Assistant?$q$, $q$Stable Diffusion refers to the underlying open-weight image model, while Stable Assistant is Stability AI's consumer application that packages that technology into a simpler, subscription-based chat and image interface.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Can I fine-tune Stable Diffusion on my own images?$q$, $q$Yes, because the model weights are open, it supports fine-tuning and related customization techniques to adapt it to specific styles, subjects, or brands.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Does Stability AI offer an API for developers?$q$, $q$Yes, Stability AI provides a hosted, credit-based developer API with multiple model tiers so applications can generate images without managing their own infrastructure.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Custom application image generation$q$, $q$Developers integrate Stable Diffusion through the API or self-hosted deployment to add image generation directly into their own products.$q$, $q$Software developers and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Marketing and content visuals$q$, $q$Creators and marketers generate original illustrations, concept art, and social content using hosted apps like Stable Assistant.$q$, $q$Marketers, designers, and independent creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Research and experimentation$q$, $q$Academics and ML researchers use the open model as a transparent baseline for studying diffusion models and generative AI techniques.$q$, $q$Researchers and academic institutions$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Custom fine-tuned model creation$q$, $q$Technical users fine-tune the open weights to build specialized checkpoints for particular art styles, brands, or subjects.$q$, $q$ML engineers and technical hobbyists$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Self-hosted (open weights)$q$, $q$Free$q$, $q$N/A$q$, $q$["Download and run open model weights on your own hardware","Full control over configuration and fine-tuning","No usage fees to Stability AI","Relies on community tools and your own compute resources"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Stable Assistant Standard$q$, $q$$9/month$q$, $q$Monthly (annual option available)$q$, $q$["Monthly credit allotment for chat and image generation","Access via web app interface","Includes a free trial period","Cancel or change plan at any time"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Stable Assistant Pro/Plus$q$, $q$$19-$49/month$q$, $q$Monthly (annual option available)$q$, $q$["Higher monthly credit allotment than Standard","Access to chat and image generation features","Includes a free trial period","Cancel or change plan at any time"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$Developer API$q$, $q$Usage-based, billed per credit$q$, $q$Pay-as-you-go$q$, $q$["Credit-based billing across multiple model tiers","Some free credits included for new accounts","Custom enterprise pricing available for high-volume use","Integrate generation directly into your own application"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Stable Diffusion is an open-weight text-to-image diffusion model originally developed by Stability AI together with researchers from CompVis at LMU Munich, Runway, and the LAION dataset initiative, and first released publicly in 2022. Unlike closed, API-only systems such as DALL-E or Midjourney, Stable Diffusion's model weights can be downloaded, inspected, fine-tuned, and run independently on a user's own hardware or cloud infrastructure, which set it apart from the moment it launched and helped seed a large ecosystem of community tools, plugins, and derivative models built on top of it.$q$, $q$Over time the model family has been developed through multiple generations, with each iteration generally improving image quality, prompt understanding, and resolution support while remaining accessible under open licensing terms for most versions. This open approach turned Stable Diffusion into a foundation that other products, plugins, and fine-tuned checkpoints are built around, rather than a single closed application controlled entirely by one vendor's release schedule and interface choices.$q$, $q$Stability AI, the London-based company behind the model, now offers several ways to use the technology beyond raw open weights: a usage-based developer API for building custom applications at scale, and consumer-facing products such as Stable Assistant that wrap the underlying models in a simpler chat and image-generation interface for people who do not want to manage their own infrastructure or GPU capacity. This layered approach means the same underlying research can reach hobbyists, startups, and larger enterprises through very different levels of technical involvement.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$who-stable-diffusion-is-for$q$, $q$Who Stable Diffusion Is For$q$, 2, ARRAY[$q$Developers and machine learning engineers who want full control over an image-generation pipeline are a core audience. Because the weights are open, they can self-host the model, fine-tune it on custom datasets, integrate it into existing applications through an API, and avoid dependence on a single vendor's interface, pricing, or product roadmap for their entire generation workflow.$q$, $q$Designers, marketers, and independent creators who need an affordable or free way to produce visual assets also fit well, particularly through Stability AI's hosted apps and API tiers, which remove the need for their own GPU hardware while still giving access to the underlying model family for illustration, concept art, and social content.$q$, $q$Researchers and academics working in computer vision or generative modeling frequently use Stable Diffusion as an open, well-documented baseline for experimentation, benchmarking, and teaching, since its architecture and training approach are far more transparent than closed commercial alternatives, making it easier to study, cite, reproduce, and build coursework or published papers around.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Non-technical users who want a completely turnkey, zero-configuration creative tool may find the self-hosted route frustrating, since running the open-weight model locally typically requires a capable GPU, familiarity with community interfaces like ComfyUI or similar tools, and some comfort with installing, configuring, and updating software over time.$q$, $q$Organizations that require guaranteed enterprise SLAs, built-in content moderation, and fully managed compliance out of the box without additional engineering work should evaluate Stability AI's enterprise offerings carefully, since open self-hosted deployments place the responsibility for safety filtering, moderation, and legal review largely on the operator rather than the vendor.$q$, $q$Users who specifically want the curated aesthetic, integrated chat workflow, or one-click polish that some closed competitors emphasize may prefer those tools directly, since getting the most out of Stable Diffusion's flexibility often means investing time in prompts, models, and settings rather than relying on a single fixed, pre-tuned house style.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Stable Diffusion supports text-to-image generation from natural-language prompts, along with image-to-image transformation, inpainting to edit specific regions of an image, and outpainting to extend an image beyond its original borders, all built on the same underlying diffusion architecture that has been refined across successive model generations.$q$, $q$Because the model is open-weight, it supports fine-tuning and lightweight adaptation techniques that let users train custom styles or subjects, and it works with a broad ecosystem of community-built extensions, control mechanisms for guiding composition and pose, and alternative checkpoints trained for specific visual styles ranging from photorealism to illustration.$q$, $q$Stability AI complements the open model with hosted access options, including a credit-based developer API offering different model tiers for varying quality and cost needs, and the Stable Assistant application, which packages generation and editing capabilities into a more conversational, ready-to-use interface for people who prefer not to manage their own deployment or GPU infrastructure. Together these options let teams choose the tradeoff between cost, control, and convenience that best fits their workflow.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', $q$the-stable-diffusion-experience$q$, $q$The Stable Diffusion Experience$q$, 2, ARRAY[$q$How Stable Diffusion feels to use depends heavily on the access path chosen. Developers running it locally or on their own servers typically interact with it through community interfaces or direct API calls, giving them granular control over sampling settings, resolution, and model checkpoints, at the cost of needing to manage their own environment, drivers, and hardware.$q$, $q$Users who go through Stability AI's hosted API or the Stable Assistant app get a more streamlined experience: prompts are submitted through a simple interface or endpoint, credits are consumed per generation, and results come back without any local setup, which trades some fine-grained control for convenience, speed, and predictable usage-based costs.$q$, $q$Across both paths, the broader experience is shaped by an active open-source community that continuously produces new fine-tuned models, control tools, and workflow templates, meaning the practical capabilities of Stable Diffusion tend to extend well beyond what Stability AI ships directly, for users willing to explore, adopt, and combine that wider ecosystem of tools, forums, and shared prompt libraries.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
