INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5355600e-7720-44d4-a9be-5558cbddc251', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Story Bible$q$, $q$A structured workspace for premise, characters, worldbuilding, and chapter-by-chapter outlines that keeps later AI generations consistent with the established story.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Write$q$, $q$Generates prose continuations that attempt to match the author's established voice and the context loaded into the Story Bible.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Describe$q$, $q$Produces sensory, multi-sense descriptions for a selected passage to help enrich scene-setting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Expand and Shrink$q$, $q$Stretches or condenses a scene to adjust pacing without rewriting it from scratch.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Rewrite$q$, $q$Offers alternate phrasings, tones, or perspectives for existing text during revision.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Feedback$q$, $q$Analyzes a draft for pacing, dialogue, and other craft elements, giving writers a critique pass before human editors see it.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Canvas$q$, $q$A visual board for mapping plot structure, story arcs, and character relationships.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Brainstorm$q$, $q$Generates names, plot twists, and worldbuilding ideas on demand when a writer is stuck.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Chat$q$, $q$A conversational assistant tuned for talking through story problems rather than general Q&A.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Plugins$q$, $q$A library of community-built prompts and workflows that extend the base toolset for specific genres or tasks.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Purpose-built for fiction, with a Story Bible that keeps characters and plot consistent across a long manuscript$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Free trial with no credit card required, so writers can test real manuscript workflows before paying$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Broad toolset covering brainstorming, drafting, descriptions, pacing, and structural feedback in one product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Plugin ecosystem lets writers customize or extend prompts for specific genres and workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Max plan's credit rollover reduces the use-it-or-lose-it pressure of a monthly credit allotment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Credit-based system can feel restrictive on the entry-level tier for writers producing long manuscripts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Not designed for non-fiction, business, or marketing writing use cases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Interface and prompt tuning are English-first, with less consistent behavior in other languages$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$AI-generated output still requires substantial editing to match a writer's personal voice$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Full novel-length projects often require the pricier Professional or Max tiers to avoid running out of credits$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Does Sudowrite have a free plan?$q$, $q$Sudowrite does not offer a permanent free plan, but it provides a free trial that does not require a credit card, letting new users try the Story Bible and core writing tools before subscribing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$What is the Story Bible?$q$, $q$The Story Bible is Sudowrite's structured planning workspace where writers define premise, characters, worldbuilding, and a chapter-by-chapter outline, which the AI then references when generating or revising prose.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Can I use Sudowrite in languages other than English?$q$, $q$Sudowrite can generate text in many languages and the Write tool tries to match a writer's input language, but the interface and prompt tuning are optimized for English, so results in other languages can be less consistent.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Do unused credits roll over to the next month?$q$, $q$On the Hobby & Student and Professional tiers, unused monthly credits generally do not carry over, while the Max tier allows unused credits to roll over for up to 12 months.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Is Sudowrite good for non-fiction or business writing?$q$, $q$Sudowrite is built specifically for fiction craft, so its features and prompts are tuned for novels, screenplays, and short stories rather than non-fiction, marketing, or technical writing.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Drafting a first novel manuscript$q$, $q$Writers build out a Story Bible with premise, characters, and outline, then use Write and Expand to move from a blank page to a full first draft chapter by chapter.$q$, $q$Debut and indie novelists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Breaking through a stuck scene$q$, $q$When a writer hits writer's block mid-scene, Brainstorm and Rewrite provide alternate directions or phrasings to get momentum back without abandoning the scene.$q$, $q$Working novelists and hobbyist writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$World-building and character development for a series$q$, $q$Canvas and Story Bible let authors map out recurring characters, settings, and plot threads that need to stay consistent across multiple books.$q$, $q$Fantasy, sci-fi, and series authors$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Getting structural feedback before submission$q$, $q$Feedback analyzes pacing, dialogue, and other craft elements in a draft, giving authors a critique pass before querying agents or self-publishing.$q$, $q$Authors preparing a manuscript for query or publication$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Hobby & Student$q$, $q$$10/month$q$, $q$Annual (monthly billing also available at a higher rate)$q$, $q$["225,000 credits per month","Full access to Story Bible and core writing tools","Free trial, no credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Professional$q$, $q$$22/month$q$, $q$Annual (monthly billing also available at a higher rate)$q$, $q$["1,000,000 credits per month","Full access to all writing tools","Feedback on written work","Suited to longer works like a novel or screenplay"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Max$q$, $q$$44/month$q$, $q$Annual (monthly billing also available at a higher rate)$q$, $q$["2,000,000 credits per month","Unused credits roll over for up to 12 months","Full access to all writing tools","Aimed at authors publishing multiple times a year"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, $q$["Tailored plans for teams, studios, or publishers","Custom credit and seat arrangements","Direct sales contact for pricing"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sudowrite is an AI writing assistant built specifically for fiction authors, positioning itself as a co-writer rather than a generic content generator. Founded in 2020 in San Francisco by Amit Gupta and James Yu, the company set out to address the loneliness and blank-page anxiety that many novelists face, using large language models tuned toward narrative craft rather than marketing or business copy.$q$, $q$The product centers on the Story Bible, a structured space where writers build out premise, characters, worldbuilding, outline, and chapter braids before drafting begins, so that later AI-generated prose stays consistent with established plot and voice. From there, writers move through tools like Write, Describe, Expand, Rewrite, Brainstorm, Canvas, Feedback, and Visualize, each addressing a different stage of the drafting and revision process.$q$, $q$Sudowrite is not free software; it runs on a credit-based subscription with a Hobby & Student tier, a Professional tier, a Max tier with rollover credits, and custom Enterprise pricing for larger teams or publishers. New users get a free trial without a credit card, letting them test the Story Bible and writing tools on a real manuscript before committing to a paid plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$who-sudowrite-is-for$q$, $q$Who Sudowrite Is For$q$, 2, ARRAY[$q$Sudowrite is aimed squarely at fiction writers, self-published authors, and genre novelists working in fantasy, romance, science fiction, mystery, and similar categories that release frequently and depend on faster drafting cycles. Writers who habitually get stuck at the outline or first-draft stage are a natural fit, since Story Bible is essentially built to move an idea into chapters quickly.$q$, $q$Screenwriters and short-story writers also use it for brainstorming scenes, generating alternate descriptions, or getting unstuck at a specific plot beat, without necessarily writing an entire novel with it. Writing groups, coaches, and students working on craft assignments can use the Hobby & Student tier as an affordable way to experiment with AI-assisted brainstorming and feedback.$q$, $q$Writers who are comfortable treating AI output as raw material, to be edited, rewritten, and folded into a manuscript in their own voice, tend to get the most value, since Sudowrite is explicit that its outputs are meant as drafts and prompts rather than finished prose.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Writers who need a general business or marketing writing tool will find Sudowrite too narrow; its prompts, Story Bible structure, and vocabulary are tuned for narrative fiction, not blog posts, ad copy, emails, or technical documentation. Non-fiction authors, journalists, and copywriters are generally better served by a general-purpose AI writing assistant.$q$, $q$Anyone opposed in principle to using AI-generated text anywhere in their creative process should also steer clear, since Sudowrite's entire premise is collaborative machine-assisted drafting. Some publishers, contests, and platforms have policies restricting or requiring disclosure of AI-assisted work, so writers should check submission guidelines before relying on it.$q$, $q$Because the product runs on a metered credit system rather than unlimited usage, heavy daily users writing very long manuscripts on the cheapest tier can burn through their monthly allotment quickly and may find the entry-level plan frustrating. Writers on a tight budget who only need occasional help may be better off with a one-off tool rather than a recurring subscription.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The Story Bible is the anchor feature: writers fill in a braindump, genre, style, and characters, then Sudowrite drafts an outline and chapter-by-chapter breakdown that stays referenced throughout the project, so later generations account for established plot points and character details. Canvas gives a visual board for mapping story structure, arcs, and relationships.$q$, $q$Write generates prose continuations in the author's own established voice, while Describe produces sensory descriptions across the five senses for a chosen passage. Expand and Shrink adjust pacing by stretching or condensing a scene, Rewrite offers alternate phrasings or tones for existing text, and Feedback analyzes a draft for pacing, dialogue, and other craft elements.$q$, $q$Brainstorm helps generate names, plot twists, or worldbuilding details on demand, Chat provides a novelist-focused conversational assistant for talking through story problems, and Visualize creates reference art for characters and settings. A plugin ecosystem lets writers extend the base toolset with community-built prompts and workflows.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279c7ff2-d20a-4f79-bdc5-e15f28fdc531', $q$the-sudowrite-experience$q$, $q$The Sudowrite Experience$q$, 2, ARRAY[$q$Sudowrite lives entirely in the browser as a purpose-built editor rather than a plugin bolted onto a word processor like Word or Google Docs, though many writers still draft in Sudowrite and paste finished chapters into their manuscript tool of choice. The interface is organized around one project per manuscript, with the Story Bible, chapter list, and generation tools all visible from the same screen.$q$, $q$Every generation draws down a pool of monthly credits, and the app shows usage as you go, so the experience feels closer to a metered utility than an all-you-can-use subscription. Heavier tools like longer Write generations or Feedback reports cost more credits than a quick Describe or Brainstorm call.$q$, $q$Because the underlying language models are general-purpose but the prompts and interface are fiction-specific, output quality depends heavily on how much context a writer has already loaded into the Story Bible. Writers who invest time upfront in characters, style, and outline tend to report noticeably more usable prose than those who prompt cold.$q$]::text[], 4);
